};

//실적상세 헤더
scwin.f_SetDtheader_detail = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

//-------------------------------------------------------------------------
// 엑셀 업로드 데이터셋헤더 생성
//-------------------------------------------------------------------------
scwin.f_ExcelUpHeaderCreate = function() {
