// 조회 필드 Clear(휴지통)
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    ed_dtFrom.setValue(scwin.strFromDate);
    ed_dtTo.setValue(scwin.strFromDate);
    ed_vehcelNo.setValue("");
    ed_vehcelNm.setValue("");
    ed_reqId.setValue("");
    ed_reqNm.setValue("");
};

scwin.f_ChkOpenCommonPopUp = function(gubun, inObj, pairObj, isCode) {
	//값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
	if(!$c.gus.cfCanOpenPopup(inObj, pairObj)){
        return;
    };	

	//짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	//검색어 세팅
	let pVal = $c.gus.cfGetValue(inObj);

	//inObj가 코드 필드일 경우 팝업
	if (isCode == null || isCode == true){
	    scwin.f_OpenCommonPopUp(gubun, pVal, '', 'T', 'T');	   
	}else{ //inObj가 코드명 필드일 경우 팝업
	    scwin.f_OpenCommonPopUp(gubun, '', pVal, 'T', 'T');
	}
};

